var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"……후우. 해냈나.","JPN":"……ふう。やり遂げたのか。","ENG":"...*Sigh...* It is done.","TWN":"……呼，做到了嗎。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"침식파가 유입되던 근원은 소실되었어. 다들 고맙네.","JPN":"侵食波が流入されていた根源は消えた。みんな、ありがとう。","ENG":"The source of the Corruption ray has disappeared shut.","TWN":"侵蝕波流入的根源消失了，謝謝大家。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"도주한 망령들은? 악기를 파괴하지 않으면 되살아날 수 있는 것 아닌가?","JPN":"逃走した亡霊たちは？　楽器を破壊しないかぎり、また蘇るのではないか？","ENG":"What about the runaway ghosts? Won't they come back to life if the instruments are not destroyed?","TWN":"逃走的鬼魂呢？如果樂器沒有被破壞的話，不是還能復活嗎？"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇지, 총사대장님. 끈질기게 살아남아서 후환을 만드는 녀석들이니까.","JPN":"そうね、銃士隊長。しつこく生き残って後々の悩みの種になるやつらだから。","ENG":"That’s right, General Musketeer. They'll come back feistier than ever.","TWN":"是的，隊長。因為她們總是能頑強地生存下去，然後製造麻煩。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"셰나는 그쪽이 제대로 한 방 먹여 줬는데…….","JPN":"シェナにはそっちが一発食らわしてやってたけど……","ENG":"Shena was severely damaged by you for sure…","TWN":"世娜被你狠狠地揍了一頓……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"마에스트로도 확실히 타격을 입었을 겁니다.","JPN":"マエストロも確かなダメージを受けたことでしょう。","ENG":"Maestra must have taken heavy damage as well.","TWN":"指揮家肯定也受到了打擊。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"빠져나갔지만 이 곳은 섬입니다. 추격한다면 금방 뒤쫓을 수 있겠죠.","JPN":"逃げはしましたが、ここは島です。追撃すればすぐ追いつくでしょう。","ENG":"Although they’ve slipped through our grasp, this is an island. If we track them down, we’ll be able to catch them in no time.","TWN":"雖然逃出去了，但這個地方是島嶼。如果去追，應該很快就能追上。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"잔향은 섬 밖을 가리키면서 사라졌도다.","JPN":"残響は島の外を示しては消えた。","ENG":"Remnants have faded out of the island.","TWN":"餘味指著島外消失了。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ARMOR_NULL","text":{"KOREA":"하늘을 향한 창들이 요란한데 바다를 넘기에는 쉽지 아니할 터. 조력하는 자의 존재가 의심스럽구나.","JPN":"空に向かって放たれた数多くの槍をかわし海を越えるのはそう簡単ではあるまい。助力する者の存在が疑わしいぞ。","ENG":"With spears plunging towards the skies and waters too deep to cross, the helper comes as unknown.","TWN":"朝向天空的聲音如此吵雜，要想越過大海應該不容易吧。幫手的存在令人懷疑。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ARMOR_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"잠깐. 우리 쪽은 이 이상 대규모로 부대가 움직이는 건 위험해.","JPN":"待って。私たちの方からこれ以上大規模に部隊を動かすのは危険だ。","ENG":"Wait. We can’t afford to move with a unit this large.","TWN":"等等，如果我們這邊再繼續大規模調動部隊就危險了。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"ELLA_BORDER_NULL_NULL","text":{"KOREA":"이 곳도 행정상으로는 공해라서 출병이 가능했던 거야.","JPN":"ここも行政上は公海だったから出兵ができたんだ。","ENG":"It was only possible to come here because these waters don’t belong to anyone on paper.","TWN":"這裡也是因為行政上屬於公海，所以才能出兵。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"CURIAN_BORDER_NULL_FAKE","text":{"KOREA":"으음. 그렇다면 개인 자격으로 움직여야 하는 건가…….","JPN":"むむ。それなら個人で動くべきか……","ENG":"Hmm. Then that means I need to act as an individual from now on...","TWN":"嗯，那樣的話，我要以個人的身份行動嗎……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CURIAN_BORDER_NULL_FAKE","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ELLA_BORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"저희 역시, 지원 요청을 받고 움직이기는 했습니다만.","JPN":"私たちも支援要請を受けて動きはしましたが。","ENG":"We are also here because of the support request.","TWN":"雖然我們也是接到支援請求後行動的。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"본래는 정식으로 성무가 인정되어야 합니다.","JPN":"本来なら正式に聖務が認められなければなりません。","ENG":"But in principle, it should be permitted as a Sacred Mission for us to be able to dispatch.","TWN":"但原本應當是正式承認的聖務。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_NULL","text":{"KOREA":"이후에도 이런 식의 협력은 양측에게 불화를 일으키리라는 걸 명심해 주시길.","JPN":"以後、このような協力は双方に不和をもたらす可能性があるということを覚えておいてください。","ENG":"Please be notified that these urgent requests would be unbeneficial to both parties.","TWN":"希望以後你也能記得，這種方式的合作會給雙方帶來不和。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"THADDEUS_PRYDWEN_NULL_NULL","text":{"KOREA":"하하, 면목 없군. 다음에 성당에 가면 반드시 신부님께 고해성사를 하겠네.","JPN":"はは、面目ない。今度聖堂に行った際は、必ず神父に告解しよう。","ENG":"Haha, apologies. I’ll make sure to confess the next time I visit church.","TWN":"哈哈，慚愧慚愧。下次去教堂，我一定會向神父懺悔的。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"THADDEUS_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"중사님, 왜 그러십니까?","JPN":"軍曹、どうなさいましたか？","ENG":"Something wrong, Sergeant?","TWN":"中士，你怎麼了？"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"윽… 편하게 좀 부르라니까요. 부담스럽다구요.","JPN":"うっ……そう呼ばないでください。気が重いんですよ。","ENG":"Urgh... Just call me something more casual. It’s cringy.","TWN":"呃……別這麼稱呼我，我很有壓力。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"별건 아니고, 그냥 조금 신경 쓰이는 게 있어서요.","JPN":"大した事ではないんですけど、ただちょっと気になることがあるんです。","ENG":"Anyway... It’s nothing big, but there is something bothering me.","TWN":"沒什麼事，我就是有點擔心。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"음?","JPN":"うむ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"지금 이대로 추격해서 마에스트로를 쓰러뜨리면……","JPN":"今このまま追撃して、マエストロを倒せば……","ENG":"If we track down Maestra and take her down, right now...","TWN":"現在這樣追擊並打倒指揮家的話……"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"레버넌트 씨는 어떻게 되나 해서요.","JPN":"レヴナントさんはどうなるのかな、と思って。","ENG":"...I'm wondering what will happen to Revenant.","TWN":"亡靈會怎樣。"},"stage":{"bg":"PRYDWEN","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"후후, 이런 배를 탈 줄은 몰랐는데 말이야……","JPN":"ふふ、こんな船に乗るなんてね……","ENG":"Fu fuu, I never thought I would get on a ship like this...","TWN":"呵呵，沒想到會坐上這種船……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"잘 숨겨 뒀어. 루나.","JPN":"よく隠しておいたわ、ルナ。","ENG":"Good work on hiding it, Luna.","TWN":"你藏得很好，露娜。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"셰나는…… 괜찮을까, 요?","JPN":"シェナは……大丈夫、でしょうか？","ENG":"Do you think... Shena is going to be all right...?","TWN":"世娜……你沒事吧？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"편하게 말해. 네가 아니었다면 우리 모두 핵이 파괴됐을 테니까.","JPN":"ため口でいいわよ。あなたがいなかったら、私たちは全員核が破壊されていたでしょうから。","ENG":"No need to act so tensed up. Our cores would have been shattered by now if it hadn't been for you.","TWN":"別這麼拘束。要不是你，我們的核心就都被毀掉了。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"우선은 육지로 가자. 방향은 읽을 줄 알아?","JPN":"まずは陸に向かいましょう。方向は読める？","ENG":"For now, we need to head towards land. Do you know how to read directions?","TWN":"先去陸地上吧。你會分辨方向嗎？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아, 네. 아니, 응.","JPN":"あっ、はい。いや、うん。","ENG":"Oh, yes, ma’am! I mean, yeah...","TWN":"啊，是的，我是說，嗯。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"부학회장님이 배를 몰 때 옆에서 조금 본 정도지만.","JPN":"副学会長が船を操ってる時に隣でちょっと見ただけだけど。","ENG":"Not very well, but I learned from watching the Vice President.","TWN":"副學會長開船的時候，我在旁邊學到了點。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"우후후, 지휘자님도 참. 바다 바람은 몸에 해롭답니다.","JPN":"うふふ、マエストロったら。潮風は体によくありませんわ。","ENG":"Fu fuu fuu, dearest Chief Conductor. The sea wind isn’t good for you.","TWN":"呵呵，指揮家也真是的，海風對身體不好。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"안에 들어가서 쉬세요. 인간으로 위장하시는 것도……","JPN":"中でお休みください。人間のふりをするのも……","ENG":"Please, go inside and rest. It’ll also be a good idea to disguise as a human–","TWN":"你進裡面休息吧，偽裝成人類也……"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"역시, 가시를 빼내야겠어요.","JPN":"やはり、トゲを抜いた方がよさそうです。","ENG":"I have decided... I will need to pull the thorn out.","TWN":"果然，得把刺拔出來。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BASS_HARMONY_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Sorry?","TWN":"什麼？"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"학회와의 빚은 청산했습니다. 그럼 다음 가야 할 곳은 정해진 셈이나 다름없죠.","JPN":"学会に借りは返しました。なら、次の目的地は決まっているも同然です。","ENG":"We have cut all loose ends with the Society. It is apparent where our next destination is going to be.","TWN":"學會的帳已經還清了。那接下來要去的地方等於早就決定好了。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"왕께서 말씀하신 대로, 시간을 끌수록 상처가 덧날 뿐이에요.","JPN":"王様のお言葉どおり、長引くほど傷がこじれるだけです。","ENG":"Just as the lord said, wounds will only worsen with time.","TWN":"就像王說的那樣，時間拖得越久，傷口越嚴重。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"크리스티나 브레히트 중사는… 현재로서 노리기 어려우니.","JPN":"クリスティーナ・ブレヒト軍曹は……現時点では狙うのが厳しいですから。","ENG":"As for Sergeant Christina Brecht... She won’t be so easy to catch.","TWN":"想對付克莉絲蒂娜·布萊希特中士……現在還有點困難。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NAME","text":{"KOREA":"보다 쉬운 쪽부터 사냥하도록 하죠.","JPN":"より簡単な方から狩りましょう。","ENG":"So we will start with easier prey.","TWN":"那就先從更容易的目標開始獵殺吧。"},"stage":{"bg":"CRUISE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NAME","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};